  if (!items.length) throw new Error('没有输入数据');

  const output = [];

  for (let i = 0; i < items.length; i++) {
    const item = items[i];
    const binary = item.binary || {};
    const keys = Object.keys(binary);
    if (!keys.length) throw new Error(`第 ${i} 条 item 没有任何 binary 数据`);

    const key = keys[0];
    const binData = binary[key];
    if (!binData) throw new Error(`第 ${i} 条 item 的 ${key} 不存在`);

    const fileName = binData.fileName || `nano_result_${Date.now()}_${i}.jpg`;

    // ✅ 关键：从 n8n 拿到真实文件 buffer（兼容 /tmp 落盘模式）
    let buffer;
    try {
      buffer = await this.helpers.getBinaryDataBuffer(i, key);
    } catch (e) {
      // 兜底：如果确实是 base64 内容（非落盘模式），再用 base64 解
      const raw = binData.data;
      if (!raw) throw new Error(`第 ${i} 条 item 的 ${key} 没有 data，且 getBinaryDataBuffer 失败：${e.message}`);
      const b64 = String(raw).replace(/^data:.*;base64,/, '');
      buffer = Buffer.from(b64, 'base64');
    }

    output.push({
      json: {
        fileName,
        fileSize: buffer.length, // ✅ 真实字节数
        binaryKey: key,
      },
      binary: {
        [key]: {
          ...binData,
          fileName,
        },
      },
    });
  }

  return output;
})();

